import { Apideck } from "@apideck/unify";
import * as fs from "fs";

function normalizeDriveIdInBase64(base64Id: string, toLowercase: boolean = true): string {
  try {
    const decoded = Buffer.from(base64Id, "base64").toString("utf8");
    const parsed = JSON.parse(decoded);
    if (parsed && typeof parsed === "object" && typeof parsed.drive_id === "string") {
      parsed.drive_id = toLowercase ? parsed.drive_id.toLowerCase() : parsed.drive_id.toUpperCase();
      return Buffer.from(JSON.stringify(parsed)).toString("base64");
    }
  } catch (e) {
    // Ignore
  }
  return base64Id;
}

async function main() {
  const apiKey = process.env.APIDECK_API_KEY;
  const appId = process.env.APIDECK_APP_ID;
  const consumerId = process.env.APIDECK_CONSUMER_ID;

  if (!apiKey || !appId || !consumerId) {
    console.error("Missing required environment variables for verification.");
    process.exit(1);
  }

  const logFilePath = "/home/user/myproject/output.log";
  if (!fs.existsSync(logFilePath)) {
    console.error("Log file output.log does not exist!");
    process.exit(1);
  }

  const logData = JSON.parse(fs.readFileSync(logFilePath, "utf8"));
  console.log("Read log data:", logData);

  const client = new Apideck({
    apiKey,
    appId,
    consumerId,
  });

  const lowercaseParentFolderId = normalizeDriveIdInBase64(logData.parent_folder_id, true);
  console.log(`Lowercase normalized parent folder ID: ${lowercaseParentFolderId}`);

  console.log(`Fetching parent folder with lowercase normalized ID...`);
  const parentFolderRes = await client.fileStorage.folders.get({
    id: lowercaseParentFolderId,
    serviceId: "onedrive",
  });

  const parentFolder = parentFolderRes.getFolderResponse?.data;
  if (!parentFolder) {
    throw new Error("Could not fetch parent folder!");
  }
  console.log("Parent folder name fetched:", parentFolder.name);

  console.log(`Fetching child folder with ID: ${logData.child_folder_id}...`);
  const childFolderRes = await client.fileStorage.folders.get({
    id: logData.child_folder_id,
    serviceId: "onedrive",
  });

  const childFolder = childFolderRes.getFolderResponse?.data;
  if (!childFolder) {
    throw new Error("Could not fetch child folder!");
  }
  console.log("Child folder name fetched:", childFolder.name);

  console.log("Child folder parentFolders chain:", childFolder.parentFolders);
  const hasParentInChain = childFolder.parentFolders.some(pf => pf.id === lowercaseParentFolderId);
  if (!hasParentInChain) {
    throw new Error(`Child folder parentFolders chain does not include lowercaseParentFolderId: ${lowercaseParentFolderId}`);
  }

  console.log("VERIFICATION SUCCESSFUL! Folder hierarchy verified successfully with lowercase drive_id in parent_folder_id.");
}

main().catch(err => {
  console.error("Verification failed:", err);
  process.exit(1);
});

